                </div>
            </div>
            <button style="background:none; border:none; color:#94a3b8; cursor:pointer;" onclick="logout()" title="登出">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" width="16" height="16"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" x2="9" y1="12" y2="12"/></svg>
            </button>
        </div>
    </aside>

    <!-- MAIN CONTENT -->
    <main class="main-content">

        <!-- VIEW: DASHBOARD -->
        <div id="view-dashboard" class="view-section active">
            <header>
                <div>
                    <h2>專案總覽儀表板</h2>
                    <p class="subtitle">全公司案場即時概況</p>
                </div>
                <div>
                    <select class="form-select" style="width:auto;" id="dashboard-filter" onchange="renderDashboard()">
                        <option value="All">顯示全部員工</option>
                    </select>
                </div>
            </header>

            <div class="grid-4" id="dashboard-stats">
                <!-- Stats injected by JS -->
            </div>

            <div class="grid-2" style="margin-top: 2rem;">
                <div class="card">
                    <h3 style="margin-bottom:1rem;">即將完工 & 重點追蹤 (30天內)</h3>
                    <table>
                        <thead>
                            <tr><th>案名</th><th>負責人</th><th>階段</th><th>完工日</th></tr>
                        </thead>
                        <tbody id="dashboard-table">
