                        </tbody>
                    </table>
                </div>
                <div class="card">
                    <h3 style="margin-bottom:1rem;">案場階段統計</h3>
                    <div id="stage-chart" style="height: 200px; display:flex; align-items:flex-end; gap:1rem; padding-bottom:1rem; border-bottom:1px solid var(--border);">
                        <!-- Simple CSS Bar Chart injected by JS -->
                    </div>
                </div>
            </div>
        </div>

        <!-- VIEW: PROJECTS -->
        <div id="view-projects" class="view-section">
            <header>
                <div>
                    <h2>專案列表</h2>
                    <p class="subtitle" id="project-list-subtitle">管理所有進行中的案場</p>
                </div>
                <button class="btn btn-primary" onclick="openModal()">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
                    新增案場
                </button>
            </header>
            <div class="grid-3" id="projects-grid">
                <!-- Project Cards injected by JS -->
            </div>
        </div>

        <!-- VIEW: PROJECT DETAIL -->
        <div id="view-detail" class="view-section">
            <header>
                <div style="display:flex; align-items:center; gap:1rem;">
                    <button class="btn btn-secondary" onclick="switchView('projects')">
